<?php
namespace app\Services; use app\Repositories\BorrowRepository; use app\Repositories\InventoryRepository; use app\Repositories\MemberRepository; use app\Repositories\Database; use app\Requests\Validator;
class BorrowService{ private BorrowRepository $borrows; private InventoryRepository $items; private MemberRepository $members; public function __construct(){ $this->borrows=new BorrowRepository(); $this->items=new InventoryRepository(); $this->members=new MemberRepository(); } public function all($q='',$status='borrowing'){return $this->borrows->all($q,$status);} public function find($id){return $this->borrows->find((int)$id);} public function allItems(){return $this->items->allItems();} private function validateBorrow(array $d):array{ $e=Validator::required($d,['member_id'=>'Thành viên','item_type'=>'Loại tài liệu','item_id'=>'Tài liệu','borrow_date'=>'Ngày mượn','due_date'=>'Ngày hẹn trả']); if(!empty($d['borrow_date'])&&!empty($d['due_date'])&&strtotime($d['due_date'])<strtotime($d['borrow_date']))$e['due_date']='Ngày hẹn trả phải sau hoặc bằng ngày mượn'; return $e; } public function create(array $d):array{ $e=$this->validateBorrow($d); if($e)return ['ok'=>false,'errors'=>$e]; $item=$this->items->findItem($d['item_type'],(int)$d['item_id']); if(!$item)return ['ok'=>false,'message'=>'Tài liệu không tồn tại']; if((int)$item['quantity']<=0)return ['ok'=>false,'message'=>'Tài liệu đã hết, không thể cho mượn']; if($this->members->unreturnedCount((int)$d['member_id'])>=MAX_UNRETURNED_ITEMS)return ['ok'=>false,'message'=>'Thành viên đã mượn tối đa '.MAX_UNRETURNED_ITEMS.' tài liệu chưa trả']; $pdo=Database::connection(); try{$pdo->beginTransaction(); $id=$this->borrows->create($d); $this->items->decrease($d['item_type'],(int)$d['item_id']); $pdo->commit(); return ['ok'=>true,'data'=>$this->find($id)];}catch(\Throwable $ex){$pdo->rollBack();return ['ok'=>false,'message'=>'Lỗi tạo phiếu mượn: '.$ex->getMessage()];}} public function update(int $id,array $d):array{ $old=$this->find($id); if(!$old)return ['ok'=>false,'message'=>'Phiếu mượn không tồn tại']; if($old['status']!=='borrowing')return ['ok'=>false,'message'=>'Chỉ được sửa phiếu đang mượn']; $e=$this->validateBorrow($d); if($e)return ['ok'=>false,'errors'=>$e]; $pdo=Database::connection(); try{$pdo->beginTransaction(); if($old['item_type']!==$d['item_type']||(int)$old['item_id']!==(int)$d['item_id']){ $this->items->increase($old['item_type'],(int)$old['item_id']); $new=$this->items->findItem($d['item_type'],(int)$d['item_id']); if(!$new||$new['quantity']<=0) throw new \Exception('Tài liệu mới đã hết hoặc không tồn tại'); $this->items->decrease($d['item_type'],(int)$d['item_id']); } $d['status']='borrowing'; $this->borrows->update($id,$d); $pdo->commit(); return ['ok'=>true,'data'=>$this->find($id)];}catch(\Throwable $ex){$pdo->rollBack();return ['ok'=>false,'message'=>'Lỗi sửa phiếu mượn: '.$ex->getMessage()];}} public function delete(int $id):array{ $b=$this->find($id); if(!$b)return ['ok'=>false,'message'=>'Phiếu mượn không tồn tại']; if($b['status']!=='borrowing')return ['ok'=>false,'message'=>'Chỉ xóa được phiếu đang mượn']; $pdo=Database::connection(); try{$pdo->beginTransaction(); $this->borrows->delete($id); $this->items->increase($b['item_type'],(int)$b['item_id']); $pdo->commit(); return ['ok'=>true];}catch(\Throwable $ex){$pdo->rollBack();return ['ok'=>false,'message'=>'Lỗi xóa phiếu mượn: '.$ex->getMessage()];}}}
